;(() => {
  const ready = (fn) => {
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', fn, { once: true });
    else fn();
  };

  ready(() => {
    const moreBtn = document.querySelector('.social-more');
    const panel = document.querySelector('.social-more-panel');
    const backdrop = document.querySelector('.social-more-backdrop');
    const closeBtn = document.querySelector('.social-panel-close');
    if (!moreBtn || !panel || !backdrop || !closeBtn) return;

    const openPanel = () => {
      panel.hidden = false;
      backdrop.hidden = false;
      requestAnimationFrame(() => {
        panel.classList.add('is-open');
        backdrop.classList.add('is-open');
      });
      moreBtn.setAttribute('aria-expanded', 'true');
    };

    const closePanel = () => {
      panel.classList.remove('is-open');
      backdrop.classList.remove('is-open');
      moreBtn.setAttribute('aria-expanded', 'false');
      window.setTimeout(() => {
        if (!panel.classList.contains('is-open')) {
          panel.hidden = true;
          backdrop.hidden = true;
        }
      }, 180);
    };

    moreBtn.addEventListener('click', () => {
      if (panel.classList.contains('is-open')) closePanel();
      else openPanel();
    });
    closeBtn.addEventListener('click', closePanel);
    backdrop.addEventListener('click', closePanel);
    document.addEventListener('keydown', (event) => {
      if (event.key === 'Escape') closePanel();
    });
  });
})();


;(() => {
  const go = (url) => {
    if (!url) return;
    window.location.href = url;
  };

  document.addEventListener('click', (event) => {
    const target = event.target && event.target.closest ? event.target.closest('a[href]') : null;
    if (!target) return;
    const href = target.getAttribute('href') || '';
    const routeMap = {
      '/pages/about.html': '/pages/about.html',
      '/pages/map.html': '/pages/map.html',
      '/pages/sustainability.html': '/pages/sustainability.html'
    };
    if (routeMap[href]) {
      event.preventDefault();
      event.stopPropagation();
      go(routeMap[href]);
    }
  }, true);
})();


;(() => {
  const normalize = (href) => {
    if (!href) return '';
    const map = {
      '/about': '/pages/about.html',
      '/map': '/pages/map.html',
      '/sustainability': '/pages/sustainability.html',
      '/pages/about': '/pages/about.html',
      '/pages/map': '/pages/map.html',
      '/pages/sustainability': '/pages/sustainability.html',
      '/pages/about.html': '/pages/about.html',
      '/pages/map.html': '/pages/map.html',
      '/pages/sustainability.html': '/pages/sustainability.html'
    };
    return map[href] || '';
  };
  document.addEventListener('click', (event) => {
    const target = event.target && event.target.closest ? event.target.closest('a[href]') : null;
    if (!target) return;
    const href = target.getAttribute('href') || '';
    const url = normalize(href);
    if (!url) return;
    event.preventDefault();
    event.stopPropagation();
    window.location.assign(url);
  }, true);
})();
